/// The padding that should be applied to the workspace as a whole.
pub const WORKSPACE_PADDING: f32 = 1.0;

/// Environment Runtime app-level heartbeat. SSH keepalive only proves the
/// transport socket is alive eventually; this checks that the remote runtime
/// request/response loop is still usable and surfaces stale Connected states.
const ENVIRONMENT_RUNTIME_HEARTBEAT_INTERVAL: Duration = Duration::from_secs(60);
const ENVIRONMENT_RUNTIME_HEARTBEAT_TIMEOUT: Duration = Duration::from_secs(15);
const ENVIRONMENT_RUNTIME_HEARTBEAT_COMMAND: &str = "printf ashide-runtime-heartbeat";
const ENVIRONMENT_RUNTIME_PREPARATION_TIMEOUT: Duration = Duration::from_secs(300);
const ENVIRONMENT_RUNTIME_INSTALLATION_TIMEOUT: Duration = Duration::from_secs(900);
const ENVIRONMENT_RUNTIME_CONTROL_SOCKET_DIR: &str = "/tmp/ashe";
const WORKSPACE_SESSIONS_REFRESH_TOAST_ID: &str = "workspace_sessions_refresh";
const ENVIRONMENT_RUNTIME_FAILURE_TOAST_PREFIX: &str = "environment_runtime_failure:";

/// The minimum font size at which terminal text will be rendered.
const MIN_FONT_SIZE: f32 = 5.0;

/// The maximum font size at which terminal text will be rendered.
const MAX_FONT_SIZE: f32 = 25.0;

/// The increment for increasing/decreasing the font size.
const FONT_SIZE_INCREMENT: f32 = 1.0;

pub const TAB_BAR_HEIGHT: f32 = 34.;
/// Height for all panel headers (tab bar, Ashide Drive, resource center, theme chooser, etc.).
/// This ensures consistent header heights across all UI panels.
pub const PANEL_HEADER_HEIGHT: f32 = TAB_BAR_HEIGHT;
/// The hover area height for states where the tab bar is revealed on hover.
const TAB_BAR_HOVER_HEIGHT: f32 = 12.;
const TAB_BAR_PADDING_LEFT: f32 = 4.;
const TAB_BAR_PADDING_RIGHT: f32 = 8.;
const TITLE_BAR_SEARCH_BAR_MAX_WIDTH: f32 = 320.;
const TITLE_BAR_SEARCH_BAR_SLOT_PADDING: f32 = 8.;
const ENVIRONMENT_STRIP_CHIP_HEIGHT: f32 = 24.;

// The total height taken up by the tab bar, including its bottom border.
pub const TOTAL_TAB_BAR_HEIGHT: f32 = TAB_BAR_HEIGHT + TAB_BAR_BORDER_HEIGHT;

const TAB_BAR_ICON_PADDING: f32 = 4.;

const TAB_BAR_PILL_WIDTH: f32 = 100.;
const PILL_FONT_SIZE: f32 = 12.;
// We use the word "Ashide" in the Update Ready button to make it obvious that the terminal is Ashide.
