    fn environment_runtime_lifecycle_for_authority(
        &self,
        authority: &str,
    ) -> Option<EnvironmentLifecycleState> {
        self.environment_runtimes.lifecycle_for_authority(authority)
    }

    fn is_environment_runtime_connected_client_available_for_authority(
        &self,
        authority: &str,
        ctx: &AppContext,
    ) -> bool {
        let Some(target) = self.environment_runtime_target_for_authority(authority) else {
            return false;
        };
        crate::workspace::environment_runtime::client_for_session(target.session_id, ctx).is_some()
    }

    fn refresh_environment_runtime_left_panel_roots_for_authority(
        &mut self,
        authority: &str,
        ctx: &mut ViewContext<Self>,
    ) -> bool {
        let environment = self.current_environment_for_strip(ctx);
        if environment.authority_key != authority
            || !Self::should_sync_connected_left_panel_roots(&environment)
        {
            return false;
        }

        let Some(target) = self.environment_runtime_target_for_authority(authority) else {
            return false;
        };
        if crate::workspace::environment_runtime::client_for_session(target.session_id, ctx)
            .is_none()
        {
            return false;
        }

        let project_root = environment
            .active_workspace_root
            .clone()
            .or_else(|| target.root.clone())
            .unwrap_or_else(|| "/".to_owned());
        let home_root =
            self.environment_runtime_home_root_or_project_root(authority, &project_root);
        self.set_environment_runtime_browser_roots(
            target.host_id,
            project_root,
            home_root,
            Some(target.session_id),
            self.environment_runtime_lifecycle_for_authority(authority)
                .or(Some(environment.lifecycle_state)),
            false,
            ctx,
        );
        true
    }

    fn is_environment_runtime_active_for_authority(
        &self,
        authority: &str,
        ctx: &AppContext,
    ) -> bool {
        match self.environment_runtime_lifecycle_for_authority(authority) {
            Some(EnvironmentLifecycleState::Connected) => {
                if self
                    .is_environment_runtime_connected_client_available_for_authority(authority, ctx)
                {
                    true
                } else {
                    log::warn!(
                        "ASHIDE_ENV_RUNTIME authority={authority} is marked Connected but has no runtime client; will reconnect"
                    );
                    false
                }
            }
            Some(
                EnvironmentLifecycleState::Connecting
                | EnvironmentLifecycleState::Installing
                | EnvironmentLifecycleState::Reconnecting,
            ) => {
                if self.has_environment_runtime_bootstrap_session(authority) {
                    true
                } else {
                    log::warn!(
                        "ASHIDE_ENV_RUNTIME authority={authority} is marked preparing but has no runtime session; will reconnect"
                    );
                    false
                }
            }
            Some(EnvironmentLifecycleState::Dormant | EnvironmentLifecycleState::Error) | None => {
                false
            }
        }
    }

    fn environment_runtime_target_for_authority(
        &self,
        authority: &str,
    ) -> Option<EnvironmentRuntimeTarget> {
        self.environment_runtimes
            .connected_target_for_authority(authority)
    }

    fn is_environment_runtime_connected_for_authority(&self, authority: &str) -> bool {
        self.environment_runtime_target_for_authority(authority)
            .is_some()
    }

    /// Resolves a connected environment-runtime `HostId` for an SSH config
    /// `node_id` (the id the SFTP file browser is opened with).
    ///
    /// The environment system indexes runtimes by `authority_key`, and an SSH
    /// environment's authority is `ssh:{node_id}` (see
    /// `source_saved_ssh::runtime_transport_snapshot` /
    /// `provider_candidate_from_config`). `OpenEnvironment` and
    /// `OpenProviderFileBrowserPane` are emitted with the *same* `node_id`, so
    /// the file browser can derive that authority and look up the active
    /// runtime. Returns the `HostId` only when a runtime exists for that
    /// authority and is in the Connected state (so the daemon file RPCs are
    /// usable); otherwise `None`.
    pub(crate) fn connected_environment_runtime_host_id_for_node(
        &self,
        node_id: &str,
    ) -> Option<warp_core::HostId> {
        let authority = format!("ssh:{node_id}");
        self.environment_runtime_target_for_authority(&authority)
            .map(|target| target.host_id)
    }

