    pub fn open_or_toggle_local_drive(
        &mut self,
        toggle: bool,
        explicit_user_action: bool,
        ctx: &mut ViewContext<Self>,
    ) {
        // Closing all left panels will also close Ashide Drive so we need to retrieve
        // whether Ashide Drive was open first, and toggle based on the initial value.
        let was_local_drive_open = self.current_workspace_state.is_local_drive_open;
        self.current_workspace_state.close_all_left_panels();
        self.current_workspace_state.is_local_drive_open =
            if toggle { !was_local_drive_open } else { true };

        // Set selected object to None upon toggle close of Ashide Drive
        if !self.current_workspace_state.is_local_drive_open {
            self.set_selected_object(None, ctx);
            self.focus_active_tab(ctx);
        }

        // Reset focused index when opening/toggling Ashide Drive open
        if self.current_workspace_state.is_local_drive_open {
            self.reset_focused_index_in_local_drive(true, ctx);
        }

        ctx.notify();

        // Welcome tip logic is only for when the user explicitly opens Ashide Drive
        // AND Ashide Drive wasn't open before. There are other scenarios where we open Ashide Drive like:
        // new user onboarding, user joins a team, etc so we want to avoid counting those.
        if explicit_user_action
            && !was_local_drive_open
            && self.current_workspace_state.is_local_drive_open
        {
            self.tips_completed.update(ctx, |tips_completed, ctx| {
                mark_feature_used_and_write_to_user_defaults(
                    Tip::Action(TipAction::LocalDrive),
                    tips_completed,
                    ctx,
                );
                ctx.notify();
            });
        }
    }

