    fn handle_session_bridge_edit_dialog_event(
        &mut self,
        event: &SessionBridgeEditDialogEvent,
        ctx: &mut ViewContext<Self>,
    ) {
        self.current_workspace_state
            .is_session_bridge_edit_dialog_open = false;
        match event {
            SessionBridgeEditDialogEvent::Cancel => {
                ctx.focus(&self.left_panel_view);
            }
            SessionBridgeEditDialogEvent::Confirm { request } => {
                #[cfg(feature = "local_fs")]
                {
                    self.save_edited_conversation_session_fork(request.clone(), ctx);
                }
                #[cfg(not(feature = "local_fs"))]
                {
                    let _ = request;
                    self.show_workspace_session_error_toast(
                        "当前构建不支持本机会话历史写入".to_owned(),
                        ctx,
                    );
                }
                ctx.focus(&self.left_panel_view);
            }
        }
        ctx.notify();
    }

