    /// Opens the workflow modal in the provided space and folder with no existing content (i.e. a new workflow modal).
    fn open_workflow_modal(
        &mut self,
        _space: Space,
        initial_folder_id: Option<ObjectStoreId>,
        ctx: &mut ViewContext<Self>,
    ) {
        let Some(owner) = UserWorkspaces::as_ref(ctx).personal_drive(ctx) else {
            log::warn!("Unable to open workflow modal due to unset personal drive");
            return;
        };
        self.current_workspace_state.is_workflow_modal_open = true;
        self.workflow_modal.update(ctx, |workflow_modal, ctx| {
            workflow_modal.open_with_new(owner, initial_folder_id, ctx);
        });
        ctx.focus(&self.workflow_modal);
        ctx.notify();
    }

    /// Opens the workflow from a given [`WorkflowObject`]'s server ID.
    fn open_workflow_with_existing(
        &mut self,
        workflow_id: ObjectStoreId,
        settings: &LocalDriveObjectSettings,
        ctx: &mut ViewContext<Self>,
    ) {
        let source = WorkflowOpenSource::Existing(workflow_id);
        self.open_workflow_in_pane(&source, settings, WorkflowViewMode::Edit, ctx)
    }

    /// Opens the workflow using a mocked [`Workflow`] object as the base
    fn open_workflow_with_temporary(&mut self, workflow: Workflow, ctx: &mut ViewContext<Self>) {
        let Some(owner) = UserWorkspaces::as_ref(ctx).personal_drive(ctx) else {
            log::warn!("Unable to open temporary workflow - unset personal drive");
            return;
        };
        let source = WorkflowOpenSource::NewFromWorkflow {
            workflow: workflow.into(),
            owner,
            initial_folder_id: None,
        };
        self.open_workflow_in_pane(
            &source,
            &LocalDriveObjectSettings::default(),
            WorkflowViewMode::Create,
            ctx,
        );
    }

    /// Opens the workflow for create with a prepopulated command specified
    fn open_workflow_with_command(&mut self, command: String, ctx: &mut ViewContext<Self>) {
        let Some(owner) = UserWorkspaces::as_ref(ctx).personal_drive(ctx) else {
            log::warn!("Unable to open workflow with command - unset personal drive");
            return;
        };
        let source = WorkflowOpenSource::New {
            title: None,
            content: Some(command),
            owner,
            initial_folder_id: None,
            is_for_agent_mode: false,
        };
        self.open_workflow_in_pane(
            &source,
            &LocalDriveObjectSettings::default(),
            WorkflowViewMode::Create,
            ctx,
        );

        ctx.notify();
    }

    fn render_ai_assistant_warm_welcome(&self, appearance: &Appearance) -> Box<dyn Element> {
        let theme = appearance.theme();
        let background_color = theme.surface_2();
        let border_color = theme.surface_3();
        let sub_text_color = blended_colors::text_sub(theme, background_color);

        let header = Flex::row()
            .with_cross_axis_alignment(CrossAxisAlignment::Center)
            .with_child(
                Container::new(
                    ConstrainedBox::new(
                        WarpUiIcon::new(icons::Icon::AiAssistant.into(), *AI_ASSISTANT_LOGO_COLOR)
                            .finish(),
                    )
                    .with_width(16.)
                    .with_height(16.)
                    .finish(),
                )
                .with_margin_right(4.)
                .finish(),
            )
            .with_child(
                Text::new_inline(AI_ASSISTANT_FEATURE_NAME, appearance.ui_font_family(), 14.)
                    .with_style(Properties {
                        weight: warpui::fonts::Weight::Bold,
                        ..Default::default()
                    })
                    .finish(),
            )
            .with_child(
                Shrinkable::new(
                    1.,
                    Align::new(
                        appearance
                            .ui_builder()
                            .close_button(
                                20.,
                                self.ai_assistant_close_warm_welcome_mouse_state_handle
                                    .clone(),
                            )
                            .build()
                            .on_click(|ctx, _, _| {
                                ctx.dispatch_typed_action(
                                    WorkspaceAction::DismissAIAssistantWarmWelcome,
                                )
                            })
                            .finish(),
                    )
                    .right()
                    .finish(),
                )
                .finish(),
            )
            .finish();

        let body = appearance
            .ui_builder()
            .wrappable_text(
                "Ask Ashide AI to explain errors, suggest commands or write scripts.".to_owned(),
                true,
            )
            .with_style(UiComponentStyles {
                font_size: Some(12.),
                font_color: Some(sub_text_color),
                ..Default::default()
            })
            .build()
            .finish();

        ConstrainedBox::new(
            EventHandler::new(
                Container::new(
                    Flex::column()
                        .with_child(header)
                        .with_child(Container::new(body).with_margin_top(5.).finish())
                        .finish(),
                )
                .with_background(background_color)
                .with_corner_radius(CornerRadius::with_all(Radius::Pixels(6.)))
                .with_uniform_padding(10.)
                .with_border(Border::all(1.).with_border_color(border_color.into()))
                .finish(),
            )
            .on_left_mouse_down(|ctx, _, _| {
                ctx.dispatch_typed_action(WorkspaceAction::ClickedAIAssistantWarmWelcome);
                DispatchEventResult::StopPropagation
            })
            .finish(),
        )
        .with_height(85.)
        .with_width(210.)
        .finish()
    }

    fn render_tab_in_tab_bar(
        &self,
        tab_index: usize,
        tab_bar_state: TabBarState,
        ctx: &AppContext,
    ) -> Box<dyn Element> {
        let tab = &self.tabs[tab_index];
        let close_button_position = if FeatureFlag::TabCloseButtonOnLeft.is_enabled() {
            TabSettings::as_ref(ctx).close_button_position
        } else {
            TabCloseButtonPosition::default()
        };

        let is_drag_target = self
            .hovered_tab_index
            .as_ref()
            .is_some_and(|hovered_index| match hovered_index {
                TabBarHoverIndex::OverTab(idx) => *idx == tab_index,
                TabBarHoverIndex::BeforeTab(_) => false,
            });

        TabComponent::new(
            tab_index,
            tab_bar_state,
            tab,
            self.tab_rename_editor.clone(),
            close_button_position,
            is_drag_target,
            ctx,
        )
        .build()
        .finish()
    }

    /// Renders the tab at `tab_index` using the same render code path the live
    /// tab bar uses, so the floating chip during a cross-window tab drag
    /// matches the source tab exactly. Dispatches to the vertical tab group
    /// renderer when the source layout was vertical, and to `TabComponent`
    /// (via `render_tab_in_tab_bar`) when it was horizontal. Constructed with
    /// neutral `TabBarState` so the snapshot doesn't carry over local-drag or
    /// rename state.
    pub(crate) fn render_tab_for_drag_ghost(
        &self,
        tab_index: usize,
        was_vertical: bool,
        ctx: &AppContext,
    ) -> Box<dyn Element> {
        if tab_index >= self.tabs.len() {
            return Empty::new().finish();
        }
        if was_vertical {
            vertical_tabs::render_tab_group_for_drag_ghost(self, tab_index, ctx)
        } else {
            let tab = &self.tabs[tab_index];
            let close_button_position = if FeatureFlag::TabCloseButtonOnLeft.is_enabled() {
                TabSettings::as_ref(ctx).close_button_position
            } else {
                TabCloseButtonPosition::default()
            };
            let tab_bar_state = TabBarState {
                tab_count: self.tabs.len(),
                active_tab_index: Some(tab_index),
                is_any_tab_renaming: false,
                is_any_tab_dragging: false,
                hover_fixed_width: None,
            };
            // `.for_drag_ghost()` makes the resulting element skip the
            // outer `SavePosition`, `Draggable`, and `DropTarget` wrappers
            // so the chip overlay doesn't pollute the target window's
            // position cache (see `TabComponent::for_drag_ghost`).
            TabComponent::new(
                tab_index,
                tab_bar_state,
                tab,
                self.tab_rename_editor.clone(),
                close_button_position,
                false,
                ctx,
            )
            .for_drag_ghost()
            .build()
            .finish()
        }
    }

    fn render_left_toggle_button(
        &self,
        appearance: &Appearance,
        ctx: &AppContext,
    ) -> Box<dyn Element> {
        let vertical_tabs_active =
            FeatureFlag::VerticalTabs.is_enabled() && *TabSettings::as_ref(ctx).use_vertical_tabs;

        let (is_active, tooltip_text, action, keybinding_name, save_position_id) =
            if vertical_tabs_active {
                (
                    self.vertical_tabs_panel_open,
                    crate::t!("workspace-tabs-panel-tooltip"),
                    WorkspaceAction::ToggleVerticalTabsPanel,
                    "workspace:toggle_vertical_tabs_panel",
                    "workspace:toggle_vertical_tabs_panel",
                )
            } else {
                let tooltip = if self.left_panel_views.len() <= 1 {
                    match self
                        .left_panel_views
                        .first()
                        .copied()
                        .unwrap_or(ToolPanelView::LocalDrive)
                    {
                        ToolPanelView::ProjectExplorer => {
                            crate::t!("workspace-left-panel-project-explorer")
                        }
                        ToolPanelView::GlobalSearch { .. } => {
                            crate::t!("workspace-left-panel-global-search")
                        }
                        ToolPanelView::LocalDrive => crate::t!("workspace-left-panel-local-drive"),
                        ToolPanelView::EnvironmentProviderManager => {
                            crate::t!("workspace-left-panel-environment-provider-manager")
                        }
                        ToolPanelView::EnvironmentProjectExplorer => {
                            crate::t!("workspace-left-panel-project-explorer")
                        }
                        ToolPanelView::ServerFileBrowser => {
                            crate::t!("workspace-left-panel-server-file-browser")
                        }
                        ToolPanelView::SkillManager => {
                            crate::t!("workspace-left-panel-skill-manager")
                        }
                    }
                } else {
                    crate::t!("workspace-tools-panel-tooltip")
                };
                (
                    self.active_tab_pane_group().as_ref(ctx).left_panel_open,
                    tooltip,
                    WorkspaceAction::ToggleLeftPanel,
                    "workspace:toggle_left_panel",
                    "workspace:toggle_left_panel",
                )
            };

        SavePosition::new(
            Container::new(
                Align::new(
                    self.render_tab_bar_icon_button(
                        appearance,
                        icons::Icon::Menu,
                        &self.mouse_states.left_panel_icon,
                        action,
                        tooltip_text.to_string(),
                        keybinding_name_to_display_string(keybinding_name, ctx),
                        is_active,
                        false,
                    )
                    .finish(),
                )
                .finish(),
            )
            .finish(),
            save_position_id,
        )
        .finish()
    }

