    fn should_enable_file_tree_and_global_search_for_pane_group(pane_group: &PaneGroup) -> bool {
        pane_group
            .pane_ids()
            .filter(|id| !pane_group.is_pane_hidden_for_close(*id))
            .any(|id| {
                id.is_terminal_pane()
                    || id.is_file_pane()
                    || id.is_code_pane()
                    || id.is_code_diff_pane()
            })
    }

    fn render_right_panel_button(
        &self,
        appearance: &Appearance,
        ctx: &AppContext,
    ) -> Box<dyn Element> {
        let is_active = self.active_tab_pane_group().as_ref(ctx).right_panel_open;
        let is_enabled = Self::should_enable_file_tree_and_global_search_for_pane_group(
            self.active_tab_pane_group().as_ref(ctx),
        );
        let disable = !is_enabled;

        let theme = appearance.theme();
        let font_color = if disable {
            theme.disabled_text_color(theme.background())
        } else if is_active {
            theme.main_text_color(theme.background())
        } else {
            theme.sub_text_color(theme.background())
        };

        // Build the button content: Diff icon + optional diff stats
        let icon = ConstrainedBox::new(icons::Icon::Diff.to_warpui_icon(font_color).finish())
            .with_width(16.)
            .with_height(16.)
            .finish();

        let show_diff_stats = *TabSettings::as_ref(ctx).show_code_review_diff_stats;

        let line_changes = if show_diff_stats {
            self.active_tab_pane_group()
                .as_ref(ctx)
                .active_session_view(ctx)
                .and_then(|tv| tv.as_ref(ctx).current_diff_line_changes(ctx))
                .filter(|lc| {
                    // Only show the stat badge when there are actual line-level changes
                    // (files_changed alone, e.g. mode-only changes, is not surfaced here).
                    lc.lines_added > 0 || lc.lines_removed > 0
                })
        } else {
            None
        };

        let has_stats = line_changes.is_some();

        let mut row = Flex::row().with_cross_axis_alignment(CrossAxisAlignment::Center);
        row.add_child(icon);

        if let Some(lc) = line_changes {
            let stat = |value: u32, prefix: &str, color: ColorU| -> Box<dyn Element> {
                Container::new(
                    Text::new_inline(format!("{prefix}{value}"), appearance.ui_font_family(), 12.)
                        .with_color(color)
                        .with_style(Properties::default().weight(Weight::Semibold))
                        .finish(),
                )
                .with_margin_left(4.)
                .finish()
            };
            row.add_child(stat(lc.lines_added, "+", add_color(appearance)));
            row.add_child(stat(lc.lines_removed, "-", remove_color(appearance)));
        }

        let label = row.finish();

        // The diff icon SVG has intrinsic horizontal whitespace in its 14px viewBox: its visible
        // paths start around x=3 and end around x=11. When stats are shown, equal container padding
        // makes the gap between the button edge and the visible icon look wider than the gap after
        // the text. Locally compensate for that artwork padding without changing the shared icon.
        let (header_padding_left, header_padding_right) =
            if has_stats { (5., 8.) } else { (4., 4.) };
        let default_styles = UiComponentStyles {
            font_color: Some(font_color.into()),
            font_size: Some(12.),
            font_weight: Some(Weight::Medium),
            font_family_id: Some(appearance.ui_font_family()),
            height: Some(24.),
            border_radius: Some(CornerRadius::with_all(Radius::Pixels(4.))),
            border_width: Some(0.),
            padding: Some(Coords {
                top: 0.,
                bottom: 0.,
                left: header_padding_left,
                right: header_padding_right,
            }),
            ..Default::default()
        };

        let hover_styles = UiComponentStyles {
            background: Some(theme.surface_2().into()),
            ..default_styles
        };

        let clicked_styles = UiComponentStyles {
            background: Some(theme.background().into()),
            ..default_styles
        };

        let mut button = Button::new(
            self.mouse_states.right_panel_icon.clone(),
            default_styles,
            Some(hover_styles),
            Some(clicked_styles),
            None,
        )
        .with_custom_label(label);

        if is_active {
            button = button.active().with_active_styles(UiComponentStyles {
                background: Some(internal_colors::fg_overlay_3(theme).into()),
                ..UiComponentStyles::default()
            });
        }

        let hoverable = if disable {
            button.build().disable()
        } else {
            button
                .with_tooltip(self.render_tab_bar_icon_button_tooltip(
                    appearance,
                    crate::t!("workspace-code-review-panel-tooltip"),
                    keybinding_name_to_display_string("workspace:toggle_right_panel", ctx),
                ))
                .build()
                .on_click(move |ctx, _, _| {
                    ctx.dispatch_typed_action(WorkspaceAction::ToggleRightPanel);
                })
        };

        SavePosition::new(
            Container::new(Align::new(hoverable.finish()).finish()).finish(),
            "workspace:right_panel_button",
        )
        .finish()
    }

    /// Renders an invisible rect for detecting hovers over the tab bar.
    fn render_tab_bar_hover_area(&self) -> Box<dyn Element> {
        self.render_tab_bar_hoverable(
            ConstrainedBox::new(Empty::new().finish())
                .with_height(TAB_BAR_HOVER_HEIGHT)
                .finish(),
        )
    }

    /// Renders the provided content wrapped in the tab bar hover behavior.
    fn render_tab_bar_hoverable(&self, content: Box<dyn Element>) -> Box<dyn Element> {
        Hoverable::new(self.tab_bar_hover_state.clone(), |_| content)
            .with_hover_out_delay(Duration::from_millis(500))
            .on_hover(|_is_hovered, ctx, _app, _position| {
                ctx.dispatch_typed_action(WorkspaceAction::SyncTrafficLights);
            })
            .finish()
    }

    fn render_tab_hover_indicator(&self, appearance: &Appearance) -> Box<dyn Element> {
        ConstrainedBox::new(
            Rect::new()
                .with_background(appearance.theme().accent())
                .finish(),
        )
        .with_height(32.)
        .with_width(4.)
        .finish()
    }

    /// Renders the insertion slot for a cross-window ghost drag in the
    /// horizontal tab bar. Shows an empty space with `fg_overlay_1`
    /// background — identical to same-window drag's origin slot.
    fn render_ghost_tab_slot(&self, appearance: &Appearance, ctx: &AppContext) -> Box<dyn Element> {
        let theme = appearance.theme();
        let width = self.tab_fixed_width.or_else(|| {
            self.tabs.first().and_then(|_| {
                ctx.element_position_by_id_at_last_frame(self.window_id, tab_position_id(0))
                    .map(|rect| rect.width())
            })
        });
        let slot = Container::new(Empty::new().finish())
            .with_background(internal_colors::fg_overlay_1(theme))
            .finish();
        let inner = if let Some(w) = width {
            ConstrainedBox::new(slot).with_width(w).finish()
        } else {
            ConstrainedBox::new(slot)
                .with_min_width(80.)
                .with_max_width(200.)
                .finish()
        };
        Shrinkable::new(1.0, inner).finish()
    }

    fn render_title_bar_search_bar(&self, appearance: &Appearance) -> Box<dyn Element> {
        let theme = appearance.theme();
        let text_color = theme.sub_text_color(theme.background());

        Hoverable::new(
            self.mouse_states.title_bar_search_bar.clone(),
            |mouse_state| {
                let row = Flex::row()
                    .with_cross_axis_alignment(CrossAxisAlignment::Center)
                    .with_spacing(10.)
                    .with_child(
                        ConstrainedBox::new(
                            icons::Icon::Search.to_warpui_icon(text_color).finish(),
                        )
                        .with_width(16.)
                        .with_height(16.)
                        .finish(),
                    )
                    .with_child(
                        Shrinkable::new(
                            1.,
                            Text::new_inline(
                                crate::t!("workspace-title-bar-search-placeholder"),
                                appearance.ui_font_family(),
                                14.,
                            )
                            .with_color(text_color.into())
                            .with_clip(ClipConfig::ellipsis())
                            .finish(),
                        )
                        .finish(),
                    )
                    .finish();

                ConstrainedBox::new(
                    Container::new(row)
                        .with_background(if mouse_state.is_hovered() {
                            internal_colors::fg_overlay_2(theme)
                        } else {
                            internal_colors::fg_overlay_1(theme)
                        })
                        .with_corner_radius(CornerRadius::with_all(Radius::Pixels(4.)))
                        .with_padding_left(16.)
                        .with_padding_right(16.)
                        .with_padding_top(4.)
                        .with_padding_bottom(4.)
                        .finish(),
                )
                .with_width(TITLE_BAR_SEARCH_BAR_MAX_WIDTH)
                .finish()
            },
        )
        .with_cursor(Cursor::PointingHand)
        .on_click(|ctx, _, _| {
            ctx.dispatch_typed_action(WorkspaceAction::OpenPalette {
                mode: PaletteMode::Command,
                source: PaletteSource::TitleBarSearchBar,
                query: None,
            });
        })
        .finish()
    }

    fn active_workspace_root_for_strip(&self, ctx: &AppContext) -> Option<String> {
        let pane_group = self.get_pane_group_view(self.active_tab_index)?;
        Self::infer_environment_root_from_node(&pane_group.as_ref(ctx).snapshot(ctx))
    }

    fn infer_environment_root_from_node(node: &PaneNodeSnapshot) -> Option<String> {
        match node {
            PaneNodeSnapshot::Leaf(LeafSnapshot { contents, .. }) => {
                Self::infer_environment_root_from_leaf(contents)
            }
            PaneNodeSnapshot::Branch(BranchSnapshot { children, .. }) => children
                .iter()
                .find_map(|(_, child)| Self::infer_environment_root_from_node(child)),
        }
    }

    fn infer_environment_root_from_leaf(contents: &LeafContents) -> Option<String> {
        match contents {
            LeafContents::Terminal(TerminalPaneSnapshot { cwd: Some(cwd), .. }) => {
                Some(cwd.clone())
            }
            LeafContents::Welcome {
                startup_directory: Some(path),
            } => Some(path.to_string_lossy().into_owned()),
            _ => None,
        }
    }

    fn contains_environment_runtime_placeholder(node: &PaneNodeSnapshot) -> bool {
        match node {
            PaneNodeSnapshot::Leaf(LeafSnapshot { contents, .. }) => {
                matches!(contents, LeafContents::EnvironmentRuntimePlaceholder)
            }
            PaneNodeSnapshot::Branch(BranchSnapshot { children, .. }) => children
                .iter()
                .any(|(_, child)| Self::contains_environment_runtime_placeholder(child)),
        }
    }

    fn environment_runtime_placeholder_leaf_index(node: &PaneNodeSnapshot) -> Option<usize> {
        fn walk(node: &PaneNodeSnapshot, next_leaf_index: &mut usize) -> Option<usize> {
            match node {
                PaneNodeSnapshot::Leaf(LeafSnapshot { contents, .. }) => {
                    let leaf_index = *next_leaf_index;
                    *next_leaf_index += 1;
                    if matches!(contents, LeafContents::EnvironmentRuntimePlaceholder) {
                        Some(leaf_index)
                    } else {
                        None
                    }
                }
                PaneNodeSnapshot::Branch(BranchSnapshot { children, .. }) => children
                    .iter()
                    .find_map(|(_, child)| walk(child, next_leaf_index)),
            }
        }

        walk(node, &mut 0)
    }

    fn active_tab_contains_environment_runtime_placeholder(&self, ctx: &AppContext) -> bool {
        self.get_pane_group_view(self.active_tab_index)
            .is_some_and(|pane_group| {
                Self::contains_environment_runtime_placeholder(
                    &pane_group.as_ref(ctx).snapshot(ctx),
                )
            })
    }

    fn active_environment_runtime_placeholder_matches_authority(
        &self,
        authority: &str,
        ctx: &AppContext,
    ) -> bool {
        self.current_environment
            .as_ref()
            .is_some_and(|environment| environment.authority_key == authority)
            && self.active_tab_contains_environment_runtime_placeholder(ctx)
    }

    fn queue_active_environment_runtime_placeholder_terminal_if_needed(
        &mut self,
        ctx: &mut ViewContext<Self>,
    ) {
        if !self.active_tab_contains_environment_runtime_placeholder(ctx) {
            return;
        }

        let Some(environment) = self.current_environment.clone() else {
            return;
        };
        if !Self::supports_environment_runtime_entry(&environment) {
            return;
        }

        let authority = environment.authority_key;
        if self.has_pending_environment_runtime_entry_for_authority(&authority) {
            return;
        }

        log::info!(
            "ASHIDE_ENV_RUNTIME queueing terminal intent for active placeholder tab {authority}"
        );
        self.queue_pending_environment_runtime_terminal(&authority, ctx);
    }

    fn current_environment_for_strip(&self, ctx: &AppContext) -> EnvironmentSnapshot {
        match self.current_environment.as_ref() {
            Some(environment)
                if Self::should_preserve_current_environment_for_strip(&environment) =>
            {
                let mut environment = environment.clone();
                let sanitized_active_workspace_root =
                    environment.active_workspace_root.take().and_then(|root| {
                        crate::workspace::environment_runtime::workspace_root_candidate_for_authority(
                            &environment.authority_key,
                            root,
                        )
                    });
                Self::set_environment_workspace_root(
                    &mut environment,
                    sanitized_active_workspace_root,
                );
                if let Some(lifecycle_state) =
                    self.environment_runtime_lifecycle_for_authority(&environment.authority_key)
                {
                    environment.lifecycle_state = lifecycle_state;
                }
                environment
            }
            _ => {
                let active_workspace_root = self.active_workspace_root_for_strip(ctx);
                crate::workspace::environment_runtime::terminal_bootstrap_environment(
                    active_workspace_root,
                )
            }
        }
    }

    fn tab_index_for_environment_authority(&self, authority_key: &str) -> Option<usize> {
        self.tabs.iter().position(|tab| {
            tab.environment
                .as_ref()
                .is_some_and(|environment| environment.authority_key == authority_key)
        })
    }

    fn open_environment_snapshots(&self, ctx: &AppContext) -> Vec<EnvironmentSnapshot> {
        let mut environments = Vec::new();
        let mut seen_authorities = HashSet::new();

        let current_environment = self.current_environment_for_strip(ctx);
        if Self::should_seed_strip_with_current_environment(&current_environment) {
            seen_authorities.insert(Self::environment_strip_dedupe_key(&current_environment));
            environments.push(current_environment.clone());
        } else {
            let terminal_bootstrap_environment =
                crate::workspace::environment_runtime::terminal_bootstrap_environment(None);
            seen_authorities.insert(Self::environment_strip_dedupe_key(
                &terminal_bootstrap_environment,
            ));
            environments.push(terminal_bootstrap_environment);
        }

        for tab in &self.tabs {
            let Some(environment) = tab.environment.as_ref() else {
                continue;
            };
            if seen_authorities.insert(Self::environment_strip_dedupe_key(environment)) {
                let mut environment = environment.clone();
                if let Some(lifecycle_state) =
                    self.environment_runtime_lifecycle_for_authority(&environment.authority_key)
                {
                    environment.lifecycle_state = lifecycle_state;
                }
                environments.push(environment);
            }
        }

        for environment in self.environment_runtime_snapshots() {
            if seen_authorities.insert(Self::environment_strip_dedupe_key(&environment)) {
                let mut environment = environment;
                if let Some(lifecycle_state) =
                    self.environment_runtime_lifecycle_for_authority(&environment.authority_key)
                {
                    environment.lifecycle_state = lifecycle_state;
                }
                environments.push(environment);
            }
        }

        if seen_authorities.insert(Self::environment_strip_dedupe_key(&current_environment)) {
            environments.push(current_environment);
        }

        environments
    }

    fn switch_to_environment_authority(
        &mut self,
        authority_key: &str,
        ctx: &mut ViewContext<Self>,
    ) {
        self.current_workspace_state
            .is_environment_provider_picker_open = false;

        if let Some(index) = self.tab_index_for_environment_authority(authority_key) {
            self.activate_tab_internal(index, ctx);
            self.queue_active_environment_runtime_placeholder_terminal_if_needed(ctx);
            self.ensure_current_environment_runtime_transport_if_needed(ctx);
            self.open_pending_environment_runtime_terminal_for_current_environment(ctx);
            self.update_left_panel_available_views(ctx);
            self.sync_session_navigator_sessions(ctx);
            ctx.notify();
            return;
        }

        if let Some(environment) = Self::terminal_bootstrap_environment_for_authority(authority_key)
        {
            self.add_environment_terminal_tab(environment, true, ctx);
            return;
        }

        let Some(environment) = self
            .open_environment_snapshots(ctx)
            .into_iter()
            .find(|environment| environment.authority_key == authority_key)
        else {
            log::warn!("switch_to_environment_authority: environment not found: {authority_key}");
            ctx.notify();
            return;
        };

        if !self.ensure_environment_tab_for_authority(authority_key, ctx) {
            self.add_tab_with_pane_layout(
                PanesLayout::EnvironmentRuntimePlaceholder,
                Arc::new(HashMap::new()),
                Some(environment.label.clone()),
                ctx,
            );
            self.apply_active_tab_environment(environment, ctx);
        }
        self.ensure_current_environment_runtime_transport_if_needed(ctx);
        self.open_pending_environment_runtime_terminal_for_current_environment(ctx);
        self.update_left_panel_available_views(ctx);
        self.sync_session_navigator_sessions(ctx);
        ctx.notify();
    }

    fn disconnect_environment_runtime_state(
        &mut self,
        authority_key: &str,
        clear_user_intents: bool,
        ctx: &mut ViewContext<Self>,
    ) {
        let session_id = self.environment_runtime_session_for_authority(authority_key);
        if clear_user_intents {
            self.release_environment_authority(authority_key);
        }
        self.remove_environment_runtime_authority(authority_key);
        self.clear_environment_runtime_home_root_for_authority(authority_key);
        self.clear_indexed_environment_cli_agent_sessions_for_authority(authority_key);
        if clear_user_intents {
            self.clear_workspace_session_restoring_for_authority(authority_key, ctx);
            self.clear_pending_environment_runtime_intents_for_authority(authority_key, ctx);
            self.clear_active_restored_workspace_session_for_authority(authority_key, ctx);
        }

        if let Some(session_id) = session_id {
            crate::workspace::environment_runtime::deregister_session(session_id, ctx);
        }
    }

    fn disconnect_environment_authority(
        &mut self,
        authority_key: &str,
        ctx: &mut ViewContext<Self>,
    ) {
        self.disconnect_environment_runtime_state(authority_key, true, ctx);

        if let Some(tab_index) = self.tab_index_for_environment_authority(authority_key) {
            if self.tabs.len() > 1 {
                self.close_tab(tab_index, true, false, ctx);
            } else {
                self.add_environment_terminal_tab(
                    crate::workspace::environment_runtime::terminal_bootstrap_environment(None),
                    true,
                    ctx,
                );
                self.close_tab(tab_index, true, false, ctx);
            }
        } else if self
            .current_environment
            .as_ref()
            .is_some_and(|environment| environment.authority_key == authority_key)
        {
            self.reset_active_tab_to_terminal_bootstrap_environment(ctx);
        }

        self.update_left_panel_available_views(ctx);
        self.sync_session_navigator_sessions(ctx);
        ctx.notify();
    }

    fn environment_lifecycle_label(state: &EnvironmentLifecycleState) -> &'static str {
        match state {
            EnvironmentLifecycleState::Connected => {
                crate::t_static!("workspace-environment-state-connected")
            }
            EnvironmentLifecycleState::Dormant => {
                crate::t_static!("workspace-environment-state-dormant")
            }
            EnvironmentLifecycleState::Connecting => {
                crate::t_static!("workspace-environment-state-connecting")
            }
            EnvironmentLifecycleState::Installing => {
                crate::t_static!("workspace-environment-state-installing")
            }
            EnvironmentLifecycleState::Reconnecting => {
                crate::t_static!("workspace-environment-state-reconnecting")
            }
            EnvironmentLifecycleState::Error => {
                crate::t_static!("workspace-environment-state-error")
            }
        }
    }

    fn environment_lifecycle_color(
        appearance: &Appearance,
        state: &EnvironmentLifecycleState,
    ) -> ColorU {
        match state {
            EnvironmentLifecycleState::Connected => add_color(appearance),
            EnvironmentLifecycleState::Dormant => appearance
                .theme()
                .sub_text_color(appearance.theme().background())
                .into(),
            EnvironmentLifecycleState::Connecting
            | EnvironmentLifecycleState::Installing
            | EnvironmentLifecycleState::Reconnecting => appearance.theme().ui_warning_color(),
            EnvironmentLifecycleState::Error => appearance.theme().ui_error_color(),
        }
    }

    fn restorable_workspace_sessions(&self) -> Vec<&WorkspaceSessionSnapshot> {
        self.restored_workspace_sessions
            .iter()
            .filter(|session| {
                matches!(
                    &session.kind,
                    WorkspaceSessionKind::Terminal
                        | WorkspaceSessionKind::AgentTerminal
                        | WorkspaceSessionKind::Welcome
                )
            })
            .collect()
    }

    fn cli_agent_from_session(session: &WorkspaceSessionSnapshot) -> Option<CLIAgent> {
        session
            .cli_agent
            .as_deref()
            .map(CLIAgent::from_serialized_name)
            .filter(|agent| !matches!(agent, CLIAgent::Unknown))
            .or_else(|| {
                session
                    .cli_command
                    .as_deref()
                    .and_then(CLIAgent::from_command_prefix)
            })
    }

    fn restored_session_root_label(session: &WorkspaceSessionSnapshot) -> Option<String> {
        session
            .cwd
            .as_deref()
            .or(session.startup_directory.as_deref())
            .map(|root| user_friendly_path(root, None).into_owned())
    }

    fn cli_agent_origin_label(origin: Option<&CliAgentSessionOrigin>) -> &'static str {
        match origin {
            Some(CliAgentSessionOrigin::CommandDetected) => {
                crate::t_static!("workspace-restored-sessions-origin-command-detected")
            }
            Some(CliAgentSessionOrigin::PluginObserved) => {
                crate::t_static!("workspace-restored-sessions-origin-plugin-observed")
            }
            None => crate::t_static!("workspace-restored-sessions-origin-unknown"),
        }
    }

    fn render_restored_session_row(
        &self,
        session: &WorkspaceSessionSnapshot,
        appearance: &Appearance,
    ) -> Box<dyn Element> {
        let theme = appearance.theme();
        let title = Self::workspace_session_label(session);
        let root = Self::restored_session_root_label(session)
            .unwrap_or_else(|| crate::t!("workspace-restored-sessions-no-root"));
        let command = session
            .cli_command
            .as_deref()
            .unwrap_or_else(|| crate::t_static!("workspace-restored-sessions-no-command"));
        let environment = session
            .environment_authority_key
            .as_deref()
            .unwrap_or_else(|| crate::t_static!("workspace-restored-sessions-no-environment"));
        let origin = Self::cli_agent_origin_label(session.cli_agent_origin.as_ref());

        let title_text = Text::new_inline(title, appearance.ui_font_family(), 12.)
            .with_color(theme.main_text_color(theme.background()).into())
            .with_style(Properties::default().weight(Weight::Semibold))
            .with_clip(ClipConfig::ellipsis())
            .finish();
        let root_text = Text::new_inline(root, appearance.ui_font_family(), 11.)
            .with_color(theme.sub_text_color(theme.background()).into())
            .with_clip(ClipConfig::ellipsis())
            .finish();
        let command_text = Text::new_inline(
            crate::t!("workspace-restored-sessions-row-command", command = command),
            appearance.ui_font_family(),
            10.,
        )
        .with_color(theme.sub_text_color(theme.background()).into())
        .with_clip(ClipConfig::ellipsis())
        .finish();
        let environment_text = Text::new_inline(
            crate::t!(
                "workspace-restored-sessions-row-environment",
                environment = environment
            ),
            appearance.ui_font_family(),
            10.,
        )
        .with_color(theme.sub_text_color(theme.background()).into())
        .with_clip(ClipConfig::ellipsis())
        .finish();
        let origin_text = Text::new_inline(
            crate::t!("workspace-restored-sessions-row-origin", origin = origin),
            appearance.ui_font_family(),
            10.,
        )
        .with_color(theme.sub_text_color(theme.background()).into())
        .with_clip(ClipConfig::ellipsis())
        .finish();

        let column = Flex::column()
            .with_spacing(2.)
            .with_child(title_text)
            .with_child(root_text)
            .with_child(command_text)
            .with_child(environment_text)
            .with_child(origin_text)
            .finish();

        let row = Container::new(column)
            .with_background(internal_colors::fg_overlay_1(theme))
            .with_border(Border::all(1.).with_border_fill(ElementFill::None))
            .with_corner_radius(CornerRadius::with_all(Radius::Pixels(5.)))
            .with_padding_left(8.)
            .with_padding_right(8.)
            .with_padding_top(7.)
            .with_padding_bottom(7.)
            .finish();

        ConstrainedBox::new(row)
            .with_width(RESTORED_WORKSPACE_SESSIONS_ROW_WIDTH)
            .finish()
    }

    fn render_restored_workspace_sessions_popover(
        &self,
        sessions: &[&WorkspaceSessionSnapshot],
        appearance: &Appearance,
    ) -> Box<dyn Element> {
        let theme = appearance.theme();
        let title = Text::new_inline(
            crate::t!("workspace-restored-sessions-popover-title"),
            appearance.ui_font_family(),
            13.,
        )
        .with_color(theme.main_text_color(theme.background()).into())
        .with_style(Properties::default().weight(Weight::Semibold))
        .finish();
        let subtitle = Text::new_inline(
            crate::t!("workspace-restored-sessions-popover-subtitle"),
            appearance.ui_font_family(),
            11.,
        )
        .with_color(theme.sub_text_color(theme.background()).into())
        .with_clip(ClipConfig::ellipsis())
        .finish();

        let mut list = Flex::column()
            .with_cross_axis_alignment(CrossAxisAlignment::Stretch)
            .with_spacing(6.)
            .with_child(title)
            .with_child(subtitle);
        for session in sessions.iter().take(6) {
            list.add_child(self.render_restored_session_row(session, appearance));
        }
        if sessions.len() > 6 {
            let remaining_session_count = sessions.len().saturating_sub(6);
            list.add_child(
                Text::new_inline(
                    crate::t!(
                        "workspace-restored-sessions-popover-more",
                        count = remaining_session_count
                    ),
                    appearance.ui_font_family(),
                    11.,
                )
                .with_color(theme.sub_text_color(theme.background()).into())
                .finish(),
            );
        }
        list.add_child(
            Text::new_inline(
                crate::t!("workspace-restored-sessions-popover-footer"),
                appearance.ui_font_family(),
                11.,
            )
            .with_color(theme.sub_text_color(theme.background()).into())
            .finish(),
        );

        ConstrainedBox::new(
            Container::new(list.finish())
                .with_background(theme.surface_1())
                .with_border(Border::all(1.).with_border_color(theme.outline().into()))
                .with_corner_radius(CornerRadius::with_all(Radius::Pixels(8.)))
                .with_padding_left(RESTORED_WORKSPACE_SESSIONS_POPOVER_HORIZONTAL_PADDING)
                .with_padding_right(RESTORED_WORKSPACE_SESSIONS_POPOVER_HORIZONTAL_PADDING)
                .with_padding_top(10.)
                .with_padding_bottom(10.)
                .finish(),
        )
        .with_width(RESTORED_WORKSPACE_SESSIONS_POPOVER_WIDTH)
        .finish()
    }

    fn render_workspace_session_restore_chip(
        &self,
        appearance: &Appearance,
        _ctx: &AppContext,
    ) -> Option<Box<dyn Element>> {
        let sessions = self.restorable_workspace_sessions();
        if sessions.is_empty() {
            return None;
        }

        let theme = appearance.theme();
        let count = sessions.len();
        let session_labels = sessions
            .iter()
            .take(3)
            .map(|session| Self::workspace_session_label(session))
            .collect::<Vec<_>>();
        let label = if count == 1 {
            crate::t!(
                "workspace-restored-sessions-chip-single",
                agent = session_labels
                    .first()
                    .cloned()
                    .unwrap_or_else(|| crate::t!("workspace-restored-sessions-agent-fallback"))
            )
        } else {
            crate::t!("workspace-restored-sessions-chip-label", count = count)
        };
        let detail = if count == 1 {
            crate::t!("workspace-restored-sessions-state-dormant")
        } else {
            session_labels.join(" / ")
        };

        let label_text = Text::new_inline(label, appearance.ui_font_family(), 12.)
            .with_color(theme.main_text_color(theme.background()).into())
            .with_style(Properties::default().weight(Weight::Semibold))
            .with_clip(ClipConfig::ellipsis())
            .finish();

        let detail_text = Text::new_inline(detail, appearance.ui_font_family(), 11.)
            .with_color(
                appearance
                    .theme()
                    .sub_text_color(appearance.theme().background())
                    .into(),
            )
            .with_clip(ClipConfig::ellipsis())
            .finish();

        let row = Flex::row()
            .with_cross_axis_alignment(CrossAxisAlignment::Center)
            .with_spacing(6.)
            .with_child(label_text)
            .with_child(detail_text)
            .finish();

        let chip = ConstrainedBox::new(
            Container::new(row)
                .with_background(internal_colors::fg_overlay_1(theme))
                .with_border(Border::all(1.).with_border_color(theme.outline().into()))
                .with_corner_radius(CornerRadius::with_all(Radius::Pixels(5.)))
                .with_padding_left(8.)
                .with_padding_right(8.)
                .with_padding_top(3.)
                .with_padding_bottom(3.)
                .finish(),
        )
        .with_min_width(140.)
        .with_max_width(360.)
        .finish();

        let popover_mouse_state = self.mouse_states.workspace_session_restore_popover.clone();
        let hoverable = Hoverable::new(
            self.mouse_states.workspace_session_restore_chip.clone(),
            |_| chip,
        )
        .with_hover_out_delay(Duration::from_millis(250))
        .on_hover(move |is_hovered, ctx, _, _| {
            if is_hovered {
                ctx.dispatch_typed_action(WorkspaceAction::SetWorkspaceSessionRestorePopoverOpen {
                    open: true,
                });
                return;
            }

            let popover_hovered = popover_mouse_state
                .lock()
                .expect("workspace session restore popover mouse state lock poisoned")
                .is_mouse_over_element();
            if !popover_hovered {
                ctx.dispatch_typed_action(WorkspaceAction::SetWorkspaceSessionRestorePopoverOpen {
                    open: false,
                });
            }
        })
        .finish();

        if self
            .current_workspace_state
            .is_workspace_session_restore_popover_open
        {
            let chip_mouse_state = self.mouse_states.workspace_session_restore_chip.clone();
            let popover = self.render_restored_workspace_sessions_popover(&sessions, appearance);
            let popover = Hoverable::new(
                self.mouse_states.workspace_session_restore_popover.clone(),
                |_| popover,
            )
            .with_hover_out_delay(Duration::from_millis(250))
            .on_hover(move |is_hovered, ctx, _, _| {
                if is_hovered {
                    ctx.dispatch_typed_action(
                        WorkspaceAction::SetWorkspaceSessionRestorePopoverOpen { open: true },
                    );
                    return;
                }

                let chip_hovered = chip_mouse_state
                    .lock()
                    .expect("workspace session restore chip mouse state lock poisoned")
                    .is_mouse_over_element();
                if !chip_hovered {
                    ctx.dispatch_typed_action(
                        WorkspaceAction::SetWorkspaceSessionRestorePopoverOpen { open: false },
                    );
                }
            })
            .finish();
            let mut stack = Stack::new().with_child(hoverable);
            stack.add_positioned_overlay_child(
                popover,
                OffsetPositioning::offset_from_parent(
                    vec2f(0., 6.),
                    ParentOffsetBounds::WindowByPosition,
                    ParentAnchor::BottomLeft,
                    ChildAnchor::TopLeft,
                ),
            );
            Some(stack.finish())
        } else {
            Some(hoverable)
        }
    }

    fn environment_display_icon(icon_kind: EnvironmentDisplayIconKind) -> icons::Icon {
        match icon_kind {
            EnvironmentDisplayIconKind::Laptop => icons::Icon::Laptop,
            EnvironmentDisplayIconKind::Server => icons::Icon::Server01,
            EnvironmentDisplayIconKind::Terminal => icons::Icon::Terminal,
        }
    }

    fn render_environment_strip_chip(
        &self,
        environment: EnvironmentSnapshot,
        is_active: bool,
        appearance: &Appearance,
    ) -> Box<dyn Element> {
        let theme = appearance.theme();
        let display =
            crate::workspace::environment_runtime::environment_display_info_for_environment(
                &environment,
            );
        let state_color =
            Self::environment_lifecycle_color(appearance, &environment.lifecycle_state);
        let label = display.chip_label.clone();
        let kind_icon = Self::environment_display_icon(display.icon_kind);
        let has_runtime_controls = display.supports_disconnect;

        let root = environment
            .active_workspace_root
            .as_deref()
            .map(|root| user_friendly_path(root, None).into_owned());

        let tooltip_label = display.tooltip_label.clone();
        let tooltip_sublabel = root
            .as_ref()
            .map(|root| crate::t!("workspace-environment-tooltip-active-root", root = root));
        let ui_builder = appearance.ui_builder().clone();
        let authority_key = environment.authority_key.clone();
        let ui_font_family = appearance.ui_font_family();

        let hoverable = Hoverable::new(MouseStateHandle::default(), |state| {
            let icon_color = if is_active {
                theme.main_text_color(theme.background()).into()
            } else {
                theme.sub_text_color(theme.background()).into()
            };
            let kind_icon = ConstrainedBox::new(kind_icon.to_warpui_icon(icon_color).finish())
                .with_width(13.)
                .with_height(13.)
                .finish();

            let status_dot = ConstrainedBox::new(
                Container::new(Empty::new().finish())
                    .with_background(state_color)
                    .with_corner_radius(CornerRadius::with_all(Radius::Pixels(3.)))
                    .finish(),
            )
            .with_width(6.)
            .with_height(6.)
            .finish();

            let mut row = Flex::row()
                .with_cross_axis_alignment(CrossAxisAlignment::Center)
                .with_main_axis_size(MainAxisSize::Min)
                .with_spacing(6.)
                .with_child(kind_icon);

            if let Some(label) = label.clone() {
                row.add_child(
                    Text::new_inline(label, ui_font_family.clone(), 12.)
                        .with_color(if is_active {
                            theme.main_text_color(theme.background()).into()
                        } else {
                            theme.sub_text_color(theme.background()).into()
                        })
                        .with_style(Properties::default().weight(Weight::Semibold))
                        .with_clip(ClipConfig::ellipsis())
                        .finish(),
                );
            }
            row.add_child(status_dot);

            if has_runtime_controls {
                let disconnect_authority_key = authority_key.clone();
                let disconnect_icon_color = theme.sub_text_color(theme.background()).into();
                let close_icon = ConstrainedBox::new(
                    icons::Icon::X
                        .to_warpui_icon(disconnect_icon_color)
                        .finish(),
                )
                .with_width(12.)
                .with_height(12.)
                .finish();
                let close_button =
                    Hoverable::new(MouseStateHandle::default(), move |button_state| {
                        let mut container = Container::new(close_icon)
                            .with_padding_left(3.)
                            .with_padding_right(3.)
                            .with_padding_top(3.)
                            .with_padding_bottom(3.)
                            .with_corner_radius(CornerRadius::with_all(Radius::Pixels(4.)));
                        if button_state.is_hovered() {
                            container =
                                container.with_background(internal_colors::fg_overlay_2(theme));
                        }
                        container.finish()
                    })
                    .with_cursor(Cursor::PointingHand)
                    .finish();
                row.add_child(
                    ConstrainedBox::new(
                        Container::new(Empty::new().finish())
                            .with_background(internal_colors::fg_overlay_3(theme))
                            .finish(),
                    )
                    .with_width(1.)
                    .with_height(14.)
                    .finish(),
                );
                row.add_child(
                    EventHandler::new(close_button)
                        .on_left_mouse_down(move |ctx, _, _| {
                            log::info!(
                                "ASHIDE_ENV_RUNTIME disconnect_environment_clicked authority={disconnect_authority_key}"
                            );
                            ctx.dispatch_typed_action(WorkspaceAction::DisconnectEnvironment {
                                authority_key: disconnect_authority_key.clone(),
                            });
                            DispatchEventResult::StopPropagation
                        })
                        .finish(),
                );
            }

            let hovered = state.is_hovered();
            let chip = ConstrainedBox::new(
                Container::new(row.finish())
                    .with_background(if is_active {
                        if hovered {
                            internal_colors::fg_overlay_3(theme)
                        } else {
                            internal_colors::fg_overlay_2(theme)
                        }
                    } else if hovered {
                        internal_colors::fg_overlay_1(theme)
                    } else {
                        theme.background()
                    })
                    .with_border(Border::all(1.).with_border_fill(if is_active {
                        internal_colors::fg_overlay_3(theme).into()
                    } else if hovered {
                        theme.outline().into()
                    } else {
                        ElementFill::None
                    }))
                    .with_corner_radius(CornerRadius::with_all(Radius::Pixels(7.)))
                    .with_padding_left(if has_runtime_controls { 9. } else { 8. })
                    .with_padding_right(if has_runtime_controls { 5. } else { 8. })
                    .with_padding_top(3.)
                    .with_padding_bottom(3.)
                    .finish(),
            )
            .with_min_width(if has_runtime_controls { 126. } else { 42. })
            .with_max_width(260.)
            .with_height(ENVIRONMENT_STRIP_CHIP_HEIGHT)
            .finish();

            let mut stack = Stack::new().with_child(chip);
            if hovered {
                let tooltip = if let Some(tooltip_sublabel) = tooltip_sublabel.clone() {
                    ui_builder
                        .tool_tip_with_sublabel(tooltip_label.clone(), tooltip_sublabel)
                        .build()
                        .finish()
                } else {
                    ui_builder.tool_tip(tooltip_label.clone()).build().finish()
                };
                stack.add_positioned_overlay_child(
                    tooltip,
                    OffsetPositioning::offset_from_parent(
                        vec2f(0., 4.),
                        ParentOffsetBounds::WindowByPosition,
                        ParentAnchor::BottomMiddle,
                        ChildAnchor::TopMiddle,
                    ),
                );
            }
            stack.finish()
        });

        let reconnectable = display.supports_reconnect;

        let chip = hoverable.with_cursor(Cursor::PointingHand).finish();
        if !is_active {
            EventHandler::new(chip)
                .on_left_mouse_down(move |ctx, _, _| {
                    log::info!(
                        "ASHIDE_ENV_RUNTIME environment_chip_clicked authority={authority_key}"
                    );
                    ctx.dispatch_typed_action(WorkspaceAction::SwitchEnvironment {
                        authority_key: authority_key.clone(),
                    });
                    DispatchEventResult::StopPropagation
                })
                .finish()
        } else if reconnectable {
            EventHandler::new(chip)
                .on_left_mouse_down(|ctx, _, _| {
                    ctx.dispatch_typed_action(WorkspaceAction::ReconnectCurrentEnvironment);
                    DispatchEventResult::StopPropagation
                })
                .finish()
        } else {
            chip
        }
    }

    fn environment_provider_config_path(path: &str) -> PathBuf {
        if let Some(rest) = path.strip_prefix("~/") {
            if let Some(home) = dirs::home_dir() {
                return home.join(rest);
            }
        }
        PathBuf::from(path)
    }

    fn render_environment_provider_picker_row(
        &self,
        candidate: &environment_provider::EnvironmentProviderCandidate,
        appearance: &Appearance,
    ) -> Box<dyn Element> {
        let theme = appearance.theme();
        let main_text_color = theme.main_text_color(theme.background()).into_solid();
        let sub_text_color = theme.sub_text_color(theme.background()).into_solid();
        let alias = candidate.alias.clone();
        let authority_key = candidate.authority_key.clone();
        let is_current = self
            .current_environment
            .as_ref()
            .is_some_and(|environment| environment.authority_key == authority_key);
        let is_open = self
            .tab_index_for_environment_authority(&authority_key)
            .is_some();

        let title = Text::new_inline(candidate.title.clone(), appearance.ui_font_family(), 12.)
            .with_color(main_text_color)
            .with_style(Properties::default().weight(Weight::Semibold))
            .with_clip(ClipConfig::ellipsis())
            .finish();

        let detail = candidate.detail.clone();

        let detail_text = Text::new_inline(detail, appearance.ui_font_family(), 11.)
            .with_color(sub_text_color)
            .with_clip(ClipConfig::ellipsis())
            .finish();
        let text_column = Flex::column()
            .with_main_axis_size(MainAxisSize::Min)
            .with_cross_axis_alignment(CrossAxisAlignment::Start)
            .with_spacing(3.)
            .with_child(title)
            .with_child(detail_text)
            .finish();

        let row_content = Flex::row()
            .with_main_axis_size(MainAxisSize::Max)
            .with_cross_axis_alignment(CrossAxisAlignment::Center)
            .with_child(Expanded::new(1., text_column).finish())
            .finish();

        let row = Hoverable::new(MouseStateHandle::default(), move |state| {
            let mut container = Container::new(row_content)
                .with_padding_left(8.)
                .with_padding_right(8.)
                .with_padding_top(6.)
                .with_padding_bottom(6.)
                .with_corner_radius(CornerRadius::with_all(Radius::Pixels(6.)));
            if is_current {
                container = container.with_background(if state.is_hovered() {
                    internal_colors::fg_overlay_3(theme)
                } else {
                    internal_colors::fg_overlay_2(theme)
                });
            } else if state.is_hovered() || is_open {
                container = container.with_background(internal_colors::fg_overlay_1(theme));
            }
            container.finish()
        })
        .with_cursor(Cursor::PointingHand)
        .finish();

        ConstrainedBox::new(
            EventHandler::new(row)
                .on_left_mouse_down(move |ctx, _, _| {
                    log::info!("ASHIDE_ENV_PROVIDER picker_row_clicked alias={alias}");
                    ctx.dispatch_typed_action(WorkspaceAction::OpenEnvironmentProviderCandidate {
                        alias: alias.clone(),
                    });
                    DispatchEventResult::StopPropagation
                })
                .finish(),
        )
        .with_width(ENVIRONMENT_PROVIDER_PICKER_ROW_WIDTH)
        .finish()
    }

    fn render_environment_provider_picker_popover(
        &self,
        appearance: &Appearance,
    ) -> Box<dyn Element> {
        let theme = appearance.theme();
        let load_result = environment_provider::load_provider_candidates();
        let path = load_result
            .path
            .as_ref()
            .cloned()
            .unwrap_or_else(|| "~/.ssh/config".into());
        let config_path = Self::environment_provider_config_path(&path);
        let main_text_color = theme.main_text_color(theme.background()).into_solid();

        let title = Text::new_inline(
            crate::t!("workspace-environment-provider-picker-title"),
            appearance.ui_font_family(),
            13.,
        )
        .with_color(main_text_color)
        .with_style(Properties::default().weight(Weight::Semibold))
        .finish();

        let config_button_tooltip = crate::t!("workspace-environment-provider-picker-open-config");
        let ui_builder = appearance.ui_builder().clone();
        let config_button = icon_button_with_color(
            appearance,
            icons::Icon::EditLine,
            false,
            self.mouse_states
                .environment_provider_picker_config_button
                .clone(),
            theme.sub_text_color(theme.background()),
        )
        .with_hovered_styles(UiComponentStyles {
            font_color: Some(theme.main_text_color(theme.background()).into()),
            background: Some(internal_colors::fg_overlay_2(theme).into()),
            ..UiComponentStyles::default()
        })
        .with_tooltip(move || {
            ui_builder
                .tool_tip(config_button_tooltip.clone())
                .build()
                .finish()
        })
        .build()
        .on_click(move |ctx, _, _| {
            ctx.dispatch_typed_action(WorkspaceAction::OpenFilePath {
                path: config_path.clone(),
            });
        });

        let header = Flex::row()
            .with_cross_axis_alignment(CrossAxisAlignment::Center)
            .with_child(Expanded::new(1., title).finish())
            .with_child(config_button.finish())
            .finish();

        let mut list = Flex::column().with_spacing(9.).with_child(header);
        let mut rows = Flex::column().with_spacing(2.);

        match load_result.outcome {
            environment_provider::EnvironmentProviderCandidateLoadOutcome::Loaded(candidates)
                if candidates.is_empty() =>
            {
                rows.add_child(
                    Text::new_inline(
                        crate::t!("workspace-environment-provider-picker-empty"),
                        appearance.ui_font_family(),
                        11.,
                    )
                    .with_color(theme.sub_text_color(theme.background()).into())
                    .finish(),
                );
            }
            environment_provider::EnvironmentProviderCandidateLoadOutcome::Loaded(candidates) => {
                for candidate in candidates.iter() {
                    rows.add_child(
                        self.render_environment_provider_picker_row(candidate, appearance),
                    );
                }
            }
            environment_provider::EnvironmentProviderCandidateLoadOutcome::NotFound => {
                rows.add_child(
                    Text::new_inline(
                        crate::t!("workspace-environment-provider-picker-not-found"),
                        appearance.ui_font_family(),
                        11.,
                    )
                    .with_color(theme.sub_text_color(theme.background()).into())
                    .finish(),
                );
            }
            environment_provider::EnvironmentProviderCandidateLoadOutcome::Error(message) => {
                rows.add_child(
                    Text::new_inline(
                        crate::t!(
                            "workspace-environment-provider-picker-error",
                            message = message
                        ),
                        appearance.ui_font_family(),
                        11.,
                    )
                    .with_color(theme.ui_error_color().into())
                    .finish(),
                );
            }
        }

        let scrollable_rows = ClippedScrollable::vertical(
            self.mouse_states
                .environment_provider_picker_scroll_state
                .clone(),
            rows.finish(),
            ScrollbarWidth::Auto,
            theme.disabled_text_color(theme.surface_1()).into(),
            theme.main_text_color(theme.surface_1()).into(),
            theme.surface_1().into(),
        )
        .with_overlayed_scrollbar()
        .with_padding_end(0.)
        .with_padding_start(0.)
        .finish();

        list.add_child(
            ConstrainedBox::new(scrollable_rows)
                .with_max_height(ENVIRONMENT_PROVIDER_PICKER_MAX_HEIGHT)
                .finish(),
        );

        let popover = ConstrainedBox::new(
            Container::new(list.finish())
                .with_background(theme.surface_1())
                .with_border(
                    Border::all(1.).with_border_color(coloru_with_opacity(main_text_color, 16)),
                )
                .with_corner_radius(CornerRadius::with_all(Radius::Pixels(12.)))
                .with_padding_left(ENVIRONMENT_PROVIDER_PICKER_HORIZONTAL_PADDING)
                .with_padding_right(ENVIRONMENT_PROVIDER_PICKER_HORIZONTAL_PADDING)
                .with_padding_top(10.)
                .with_padding_bottom(10.)
                .finish(),
        )
        .with_width(ENVIRONMENT_PROVIDER_PICKER_WIDTH)
        .finish();

        popover
    }

    fn render_environment_provider_picker_dismiss_target(
        &self,
        appearance: &Appearance,
    ) -> Box<dyn Element> {
        let anchor_hit_target = ConstrainedBox::new(Rect::new().finish())
            .with_width(ENVIRONMENT_STRIP_ADD_PROVIDER_CHIP_WIDTH)
            .with_height(ENVIRONMENT_STRIP_CHIP_HEIGHT)
            .finish();

        let mut dismiss_target = Stack::new().with_child(anchor_hit_target);
        dismiss_target.add_positioned_child(
            self.render_environment_provider_picker_popover(appearance),
            OffsetPositioning::offset_from_parent(
                vec2f(
                    0.,
                    ENVIRONMENT_STRIP_CHIP_HEIGHT + ENVIRONMENT_PROVIDER_PICKER_ANCHOR_GAP,
                ),
                ParentOffsetBounds::Unbounded,
                ParentAnchor::TopLeft,
                ChildAnchor::TopLeft,
            ),
        );
        dismiss_target.finish()
    }

    fn render_environment_strip_add_provider_chip(
        &self,
        appearance: &Appearance,
    ) -> Box<dyn Element> {
        let theme = appearance.theme();
        let picker_open = self
            .current_workspace_state
            .is_environment_provider_picker_open;
        let hoverable = Hoverable::new(
            self.mouse_states
                .environment_strip_add_provider_chip
                .clone(),
            move |state| {
                let icon_color = if picker_open || state.is_hovered() {
                    theme.main_text_color(theme.background()).into()
                } else {
                    theme.sub_text_color(theme.background()).into()
                };
                let server_icon =
                    ConstrainedBox::new(icons::Icon::Server01.to_warpui_icon(icon_color).finish())
                        .with_width(13.)
                        .with_height(13.)
                        .finish();

                let chip = ConstrainedBox::new(
                    Container::new(server_icon)
                        .with_background(if picker_open || state.is_hovered() {
                            if picker_open {
                                internal_colors::fg_overlay_2(theme)
                            } else {
                                internal_colors::fg_overlay_1(theme)
                            }
                        } else {
                            theme.background()
                        })
                        .with_border(Border::all(1.).with_border_fill(if picker_open {
                            internal_colors::fg_overlay_3(theme).into()
                        } else if state.is_hovered() {
                            theme.outline().into()
                        } else {
                            ElementFill::None
                        }))
                        .with_corner_radius(CornerRadius::with_all(Radius::Pixels(7.)))
                        .with_padding_left(6.)
                        .with_padding_right(6.)
                        .with_padding_top(3.)
                        .with_padding_bottom(3.)
                        .finish(),
                )
                .with_width(ENVIRONMENT_STRIP_ADD_PROVIDER_CHIP_WIDTH)
                .with_height(ENVIRONMENT_STRIP_CHIP_HEIGHT)
                .finish();
                chip
            },
        )
        .on_hover(|is_hovered, ctx, _, _| {
            if is_hovered {
                ctx.dispatch_typed_action(WorkspaceAction::SetEnvironmentProviderPickerOpen {
                    open: true,
                });
            }
        })
        .with_cursor(Cursor::PointingHand)
        .finish();

        let hoverable = EventHandler::new(hoverable)
            .on_left_mouse_down(|ctx, _, _| {
                ctx.dispatch_typed_action(WorkspaceAction::SetEnvironmentProviderPickerOpen {
                    open: true,
                });
                DispatchEventResult::StopPropagation
            })
            .finish();

        SavePosition::new(hoverable, ENVIRONMENT_PROVIDER_PICKER_POSITION_ID).finish()
    }

    fn render_tab_bar_contents(
        &self,
        hover_fixed_width: Option<f32>,
        appearance: &Appearance,
        ctx: &AppContext,
    ) -> Box<dyn Element> {
        let mut tab_bar = Flex::row().with_cross_axis_alignment(CrossAxisAlignment::Center);
        let is_web_anonymous_user = self
            .auth_state
            .is_user_web_anonymous_user()
            .unwrap_or_default();

        // Simplified mode for viewing Ashide Drive objects, shared sessions, or conversation transcripts on WASM
        #[cfg(target_family = "wasm")]
        if let Some(content_type) = self.get_simplified_wasm_tab_bar_content(ctx) {
            // Use MainAxisAlignment::SpaceBetween and expand to fill width
            tab_bar = tab_bar
                .with_main_axis_alignment(MainAxisAlignment::SpaceBetween)
                .with_main_axis_size(MainAxisSize::Max);
            let bg_color = blended_colors::neutral_1(appearance.theme());

            // Left: Ashide logo - clickable to link to the Ashide repository.
            let warp_logo = Hoverable::new(self.mouse_states.warp_logo.clone(), |_state| {
                ConstrainedBox::new(
                    warp_core::ui::Icon::Zap
                        .to_warpui_icon(appearance.theme().foreground())
                        .finish(),
                )
                .with_height(24.)
                .with_width(24.)
                .finish()
            })
            .on_click(|ctx, _, _| {
                ctx.dispatch_typed_action(WorkspaceAction::OpenLink(
                    "https://github.com/dly023/ashide".to_owned(),
                ));
            })
            .with_cursor(Cursor::PointingHand)
            .finish();
            tab_bar.add_child(warp_logo);

            // Right: Info button + run history button (for agent sessions) + "Open in Ashide" button
            let mut right_row = Flex::row()
                .with_cross_axis_alignment(CrossAxisAlignment::Center)
                .with_main_axis_size(MainAxisSize::Min);

            // Show info button for conversation transcripts and shared sessions (if there's content to display)
            let should_show_info_button =
                !matches!(content_type, SimplifiedWasmTabBarContent::LocalDriveObject)
                    && self
                        .active_tab_pane_group()
                        .as_ref(ctx)
                        .focused_session_view(ctx)
                        .is_some_and(|view| {
                            Self::should_show_conversation_details_panel(&view, ctx)
                        });

            if should_show_info_button {
                right_row.add_child(
                    Container::new(ChildView::new(&self.transcript_info_button).finish())
                        .with_margin_right(8.)
                        .finish(),
                );
            }

            // Hide "Open in Ashide" button on mobile devices
            if !warpui::platform::wasm::is_mobile_device() {
                right_row.add_child(ChildView::new(&self.open_in_warp_button).finish());
            }
            tab_bar.add_child(right_row.finish());

            return Container::new(tab_bar.finish())
                .with_background_color(bg_color)
                .with_border(
                    Border::bottom(1.0)
                        .with_border_fill(blended_colors::neutral_2(appearance.theme())),
                )
                .with_padding_left(24.)
                .with_padding_right(24.)
                .with_padding_top(4.)
                .with_padding_bottom(4.)
                .finish();
        }

        // Check if vertical tabs mode is active
        let vertical_tabs_active =
            FeatureFlag::VerticalTabs.is_enabled() && *TabSettings::as_ref(ctx).use_vertical_tabs;

        // Render config-driven left-side toolbar buttons (both horizontal and vertical tabs)
        let knowledge_center_closed = true;
        let config = TabSettings::as_ref(ctx)
            .header_toolbar_chip_selection
            .clone();
        if knowledge_center_closed && !self.is_theme_chooser_open() {
            let left_toolbar_buttons = config
                .left_items()
                .into_iter()
                .filter_map(|item| self.render_header_toolbar_button(&item, appearance, ctx))
                .collect::<Vec<_>>();
            let left_toolbar_button_count = left_toolbar_buttons.len();
            for (index, button) in left_toolbar_buttons.into_iter().enumerate() {
                let is_last_left_toolbar_button = index + 1 == left_toolbar_button_count;
                if !vertical_tabs_active && is_last_left_toolbar_button {
                    tab_bar.add_child(Container::new(button).with_margin_right(8.).finish());
                } else {
                    tab_bar.add_child(button);
                }
            }
            if vertical_tabs_active && left_toolbar_button_count > 0 {
                tab_bar.add_child(
                    ConstrainedBox::new(Empty::new().finish())
                        .with_width(8.)
                        .finish(),
                );
            }
        }

        let active_environment = self.current_environment_for_strip(ctx);
        for environment in self.open_environment_snapshots(ctx) {
            let is_active = environment.authority_key == active_environment.authority_key;
            tab_bar.add_child(
                Container::new(self.render_environment_strip_chip(
                    environment,
                    is_active,
                    appearance,
                ))
                .with_margin_right(8.)
                .finish(),
            );
        }
        tab_bar.add_child(
            Container::new(self.render_environment_strip_add_provider_chip(appearance))
                .with_margin_right(8.)
                .finish(),
        );

        if vertical_tabs_active {
            let mut right_controls = Flex::row()
                .with_cross_axis_alignment(CrossAxisAlignment::Center)
                .with_main_axis_size(MainAxisSize::Min);

            self.add_configurable_right_side_tab_bar_controls(
                &mut right_controls,
                &config,
                is_web_anonymous_user,
                appearance,
                ctx,
            );

            let left_padding = self.compute_tab_bar_left_padding(ctx);

            let show_title_bar_search_bar = *TabSettings::as_ref(ctx).show_title_bar_search_bar;
            let mut tab_bar_row = Flex::row()
                .with_main_axis_size(MainAxisSize::Max)
                .with_cross_axis_alignment(CrossAxisAlignment::Center)
                .with_child(tab_bar.finish());
            if show_title_bar_search_bar {
                tab_bar_row.add_child(
                    Shrinkable::new(
                        1.,
                        Clipped::new(
                            Container::new(
                                Align::new(self.render_title_bar_search_bar(appearance)).finish(),
                            )
                            .with_padding_left(TITLE_BAR_SEARCH_BAR_SLOT_PADDING)
                            .with_padding_right(TITLE_BAR_SEARCH_BAR_SLOT_PADDING)
                            .finish(),
                        )
                        .finish(),
                    )
                    .finish(),
                );
            } else {
                tab_bar_row.add_child(Shrinkable::new(1., Empty::new().finish()).finish());
            }
            tab_bar_row.add_child(right_controls.finish());
            let tab_bar = tab_bar_row.finish();

            return EventHandler::new(
                Container::new(tab_bar)
                    .with_padding_left(left_padding)
                    .with_padding_right(TAB_BAR_PADDING_RIGHT)
                    .finish(),
            )
            .on_right_mouse_down(|ctx, _, position| {
                ctx.dispatch_typed_action(WorkspaceAction::ShowHeaderToolbarContextMenu {
                    position,
                });
                DispatchEventResult::StopPropagation
            })
            .finish();
        } else {
            // Copy from our saved tab_bar_state to ensure all tabs get rendered with the same state
            let active_tab_index = Some(self.active_tab_index);

            let drag_model = CrossWindowTabDrag::as_ref(ctx);
            let tab_bar_state = TabBarState {
                tab_count: self.tabs.len(),
                active_tab_index,
                is_any_tab_renaming: self.current_workspace_state.is_tab_being_renamed(),
                is_any_tab_dragging: self.current_workspace_state.is_tab_being_dragged
                    || drag_model.is_active(),
                hover_fixed_width,
            };
            // Collapse the detached-placeholder slot to 0 width while it
            // exists in this (source) window. After a put-back handoff the
            // placeholder has been removed and the real tab re-inserted at a
            // different index, so `source_placeholder_tab_index()` returns
            // `None` and nothing is hidden — otherwise the stale
            // `source_tab_index` would collapse an unrelated tab (e.g. the
            // first tab shifting into that slot after a leftward put-back).
            let transferred_tab_index = if drag_model.is_active()
                && drag_model.source_window_id() == Some(self.window_id)
            {
                let has_dedicated_preview = drag_model.has_dedicated_preview_window();
                let has_handoff = drag_model.handed_off_target().is_some();
                if has_dedicated_preview || has_handoff {
                    drag_model.source_placeholder_tab_index()
                } else {
                    None
                }
            } else {
                None
            };
            // Ghost state for cross-window drag hovering over this tab bar.
            let ghost = drag_model.ghost_state_for_window(self.window_id);

            for i in 0..self.tabs.len() {
                // Insert ghost slot before tab `i` if the drag would land here.
                if ghost.as_ref().is_some_and(|g| g.insertion_index == i) {
                    tab_bar.add_child(self.render_ghost_tab_slot(appearance, ctx));
                }
                let is_transferred = transferred_tab_index == Some(i);
                if !is_transferred
                    && self
                        .hovered_tab_index
                        .as_ref()
                        .is_some_and(|hovered_index| match hovered_index {
                            TabBarHoverIndex::BeforeTab(idx) => i == *idx,
                            TabBarHoverIndex::OverTab(_) => false,
                        })
                {
                    tab_bar.add_child(self.render_tab_hover_indicator(appearance));
                }
                if is_transferred {
                    tab_bar.add_child(
                        ConstrainedBox::new(self.render_tab_in_tab_bar(i, tab_bar_state, ctx))
                            .with_width(0.)
                            .finish(),
                    );
                } else {
                    tab_bar.add_child(self.render_tab_in_tab_bar(i, tab_bar_state, ctx));
                }
            }

            // Fencepost: ghost slot or hover indicator after all tabs.
            if ghost
                .as_ref()
                .is_some_and(|g| g.insertion_index == self.tabs.len())
            {
                tab_bar.add_child(self.render_ghost_tab_slot(appearance, ctx));
            } else if self
                .hovered_tab_index
                .as_ref()
                .is_some_and(|hovered_index| match hovered_index {
                    TabBarHoverIndex::BeforeTab(idx) => self.tabs.len() == *idx,
                    TabBarHoverIndex::OverTab(_) => false,
                })
            {
                tab_bar.add_child(self.render_tab_hover_indicator(appearance));
            }

            if ContextFlag::CreateNewSession.is_enabled() {
                tab_bar.add_child(self.render_new_session_button(ctx));
            }
        }

        // Placeholder to make sure the flex row expands across the entire width of the app.
        tab_bar.add_child(Shrinkable::new(0.5, Empty::new().finish()).finish());

        self.add_configurable_right_side_tab_bar_controls(
            &mut tab_bar,
            &config,
            is_web_anonymous_user,
            appearance,
            ctx,
        );

        let left_padding = self.compute_tab_bar_left_padding(ctx);

        EventHandler::new(
            Container::new(tab_bar.finish())
                .with_padding_left(left_padding)
                .with_padding_right(TAB_BAR_PADDING_RIGHT)
                .finish(),
        )
        .on_right_mouse_down(|ctx, _, position| {
            ctx.dispatch_typed_action(WorkspaceAction::ShowHeaderToolbarContextMenu { position });
            DispatchEventResult::StopPropagation
        })
        .finish()
    }

    /// Renders a single header toolbar button for the given item kind.
    /// Returns `None` if the item is not currently available.
    /// The button is wrapped with a right-click handler that opens the
    /// toolbar configurator.
    fn render_header_toolbar_button(
        &self,
        item: &HeaderToolbarItemKind,
        appearance: &Appearance,
        ctx: &AppContext,
    ) -> Option<Box<dyn Element>> {
        if !item.is_available(ctx) {
            return None;
        }
        let vertical_tabs_active =
            FeatureFlag::VerticalTabs.is_enabled() && *TabSettings::as_ref(ctx).use_vertical_tabs;
        let inner = match item {
            HeaderToolbarItemKind::TabsPanel => self.render_left_toggle_button(appearance, ctx),
            HeaderToolbarItemKind::ToolsPanel => {
                if self.left_panel_views.is_empty() {
                    return None;
                }
                if vertical_tabs_active {
                    self.render_tools_panel_button(appearance, ctx)
                } else {
                    self.render_left_toggle_button(appearance, ctx)
                }
            }
            HeaderToolbarItemKind::CodeReview => self.render_right_panel_button(appearance, ctx),
            HeaderToolbarItemKind::NotificationsMailbox => {
                self.render_notifications_mailbox_button(appearance, ctx)
            }
        };
        Some(
            Container::new(
                EventHandler::new(inner)
                    .on_right_mouse_down(|ctx, _, position| {
                        ctx.dispatch_typed_action(WorkspaceAction::ShowHeaderToolbarContextMenu {
                            position,
                        });
                        DispatchEventResult::StopPropagation
                    })
                    .finish(),
            )
            .with_margin_left(TAB_BAR_ICON_PADDING)
            .finish(),
        )
    }

    /// Renders the notifications mailbox button (extracted for reuse from
    /// add_right_side_tab_bar_controls).
    fn render_notifications_mailbox_button(
        &self,
        appearance: &Appearance,
        ctx: &AppContext,
    ) -> Box<dyn Element> {
        let is_inbox_active = self.current_workspace_state.is_notification_mailbox_open
            || self.hoa_onboarding_flow.as_ref().is_some_and(|flow| {
                flow.as_ref(ctx).step() == HoaOnboardingStep::AgentInboxCallout
            });
        let mailbox_button = self
            .render_tab_bar_icon_button(
                appearance,
                icons::Icon::Inbox,
                &self.mouse_states.notifications_mailbox,
                WorkspaceAction::ToggleNotificationMailbox {
                    select_first: false,
                },
                crate::t!("workspace-notifications-tooltip"),
                keybinding_name_to_display_string(TOGGLE_NOTIFICATION_MAILBOX_BINDING_NAME, ctx),
                is_inbox_active,
                false,
            )
            .finish();

        let unread_count = if FeatureFlag::HOANotifications.is_enabled() {
            NotificationsModel::as_ref(ctx)
                .notifications()
                .filtered_count(NotificationFilter::Unread)
        } else {
            0
        };
        let mailbox_element = if unread_count > 0 {
            let indicator = Container::new(
                ConstrainedBox::new(
                    Rect::new()
                        .with_background(appearance.theme().accent())
                        .with_corner_radius(CornerRadius::with_all(Radius::Percentage(50.)))
                        .finish(),
                )
                .with_width(6.)
                .with_height(6.)
                .finish(),
            )
            .finish();
            let mut stack = Stack::new();
            stack.add_child(mailbox_button);
            stack.add_positioned_child(
                indicator,
                OffsetPositioning::offset_from_parent(
                    Vector2F::zero(),
                    ParentOffsetBounds::WindowByPosition,
                    ParentAnchor::TopRight,
                    ChildAnchor::TopRight,
                ),
            );
            stack.finish()
        } else {
            mailbox_button
        };

        SavePosition::new(
            Container::new(Align::new(mailbox_element).finish()).finish(),
            NOTIFICATIONS_MAILBOX_POSITION_ID,
        )
        .finish()
    }

    /// Adds the configurable right-side toolbar items plus the fixed controls
    /// (update pill, offline indicator, avatar, etc.) that are not configurable.
    fn add_configurable_right_side_tab_bar_controls(
        &self,
        target: &mut Flex,
        config: &crate::workspace::tab_settings::HeaderToolbarChipSelection,
        is_web_anonymous_user: bool,
        appearance: &Appearance,
        ctx: &AppContext,
    ) {
        if let Some(update_pill) = self.render_tab_overflow_menu(ctx, appearance) {
            target.add_child(
                Container::new(update_pill)
                    .with_margin_left(TAB_BAR_PADDING_LEFT)
                    .finish(),
            );
        }

        let is_online = NetworkStatus::as_ref(ctx).is_online();

        if !is_online {
            target.add_child(
                Container::new(self.render_offline_button(appearance))
                    .with_margin_right(4.)
                    .finish(),
            );
        }

        for item in config.right_items() {
            if let Some(button) = self.render_header_toolbar_button(&item, appearance, ctx) {
                target.add_child(button);
            }
        }

        // Legacy AI assistant button (non-agent-mode only)
        if is_online
            && !FeatureFlag::AgentMode.is_enabled()
            && !is_web_anonymous_user
            && !self.current_workspace_state.is_ai_assistant_panel_open
        {
            target.add_child(
                Container::new(
                    SavePosition::new(
                        self.render_legacy_ai_assistant_entrypoint_button(appearance),
                        AI_ASSISTANT_BUTTON_ID,
                    )
                    .finish(),
                )
                .with_margin_left(TAB_BAR_PADDING_LEFT)
                .finish(),
            );
        }

        if FeatureFlag::AvatarInTabBar.is_enabled() {
            target.add_child(
                Container::new(self.render_avatar_button(appearance, ctx))
                    .with_margin_left(TAB_BAR_PADDING_LEFT)
                    .finish(),
            );
        } else {
            // 去中心化分支:不再渲染 Ashide Essentials(灯泡)按钮,只保留设置齿轮。
            target.add_child(
                Container::new(self.render_settings_button(appearance))
                    .with_margin_left(TAB_BAR_PADDING_LEFT)
                    .finish(),
            );
        }

        let zoom_factor = WindowSettings::as_ref(ctx).zoom_level.as_zoom_factor();
        let traffic_light_data = traffic_light_data(ctx, self.window_id);
        if let Some(traffic_light_data) = traffic_light_data.as_ref() {
            let vertical_tabs_active = FeatureFlag::VerticalTabs.is_enabled()
                && *TabSettings::as_ref(ctx).use_vertical_tabs;
            let right_panel_open = self.current_workspace_state.is_right_panel_open();
            let should_reserve_right_traffic_light_space =
                vertical_tabs_active || !right_panel_open;

            if traffic_light_data.side == TrafficLightSide::Right
                && should_reserve_right_traffic_light_space
            {
                target.add_child(
                    ConstrainedBox::new(Empty::new().finish())
                        .with_width(traffic_light_data.width(zoom_factor))
                        .finish(),
                );
            }
        }
    }

    fn compute_tab_bar_left_padding(&self, ctx: &AppContext) -> f32 {
        let zoom_factor = WindowSettings::as_ref(ctx).zoom_level.as_zoom_factor();
        let traffic_light_data = traffic_light_data(ctx, self.window_id);
        let is_window_fullscreen = ctx
            .windows()
            .platform_window(self.window_id)
            .map(|window| window.fullscreen_state() == FullscreenState::Fullscreen)
            .unwrap_or(false);
        if self.current_workspace_state.is_left_panel_open() {
            0.
        } else if is_window_fullscreen && cfg!(target_os = "macos") {
            // Full-screen mode on MacOS does not need as much padding (traffic lights are hidden).
            TAB_BAR_PADDING_LEFT
        } else {
            traffic_light_data
                .as_ref()
                .filter(|data| data.side == TrafficLightSide::Left)
                .map(|data| data.width(zoom_factor))
                .unwrap_or(0.)
                + 16.
        }
    }

    /// Renders the tab bar contents, wrapped in hover and drag-drop behaviors.
    fn render_tab_bar(
        &self,
        tab_fixed_width: Option<f32>,
        appearance: &Appearance,
        ctx: &AppContext,
    ) -> Box<dyn Element> {
        let bar_contents = ConstrainedBox::new(
            // We can wrap the whole tab bar in the a drop target with the `AfterTabIndex` drop target data since the API for accepting a drop target with nested
            // drop target elements will default to the inner ones (in this case the tabs or the button before the tabs)
            DropTarget::new(
                self.render_tab_bar_contents(tab_fixed_width, appearance, ctx),
                TabBarDropTargetData {
                    tab_bar_location: TabBarLocation::AfterTabIndex(self.tabs.len()),
                },
            )
            .finish(),
        )
        .with_height(TAB_BAR_HEIGHT)
        .finish();

        let tab_bar_border =
            Border::bottom(TAB_BAR_BORDER_HEIGHT).with_border_fill(appearance.theme().outline());

        let mut tab_bar_container = Container::new(
            EventHandler::new(Clipped::new(self.render_tab_bar_hoverable(bar_contents)).finish())
                .on_back_mouse_down(move |ctx, _app, _position| {
                    ctx.dispatch_typed_action(WorkspaceAction::ActivatePrevTab);
                    DispatchEventResult::StopPropagation
                })
                .on_forward_mouse_down(move |ctx, _app, _position| {
                    ctx.dispatch_typed_action(WorkspaceAction::ActivateNextTab);
                    DispatchEventResult::StopPropagation
                })
                .finish(),
        )
        .with_border(tab_bar_border);
        if FeatureFlag::NewTabStyling.is_enabled() {
            tab_bar_container = tab_bar_container
                .with_background(internal_colors::fg_overlay_1(appearance.theme()));
        }
        let tab_bar_element = tab_bar_container.finish();

        let dimming_color = appearance.theme().background().into();
        SavePosition::new(
            WindowFocusDimming::apply_panel_header_dimming(
                tab_bar_element,
                self.mouse_states.header_dimming.clone(),
                TAB_BAR_HEIGHT,
                dimming_color,
                self.window_id,
                ctx,
            ),
            TAB_BAR_POSITION_ID,
        )
        .finish()
    }

    // Render traffic lights, if appropriate for the current platform.
    fn maybe_render_traffic_lights(&self, stack: &mut Stack, app: &AppContext) {
        let Some(traffic_light_data) = traffic_light_data(app, self.window_id) else {
            return;
        };

        let appearance = Appearance::as_ref(app);
        let fullscreen_state = app
            .windows()
            .platform_window(self.window_id)
            .map(|window| window.fullscreen_state())
            .unwrap_or_default();
        stack.add_positioned_child(
            traffic_light_data.render(
                fullscreen_state,
                &self.traffic_light_mouse_states,
                appearance.theme(),
                app,
            ),
            OffsetPositioning::offset_from_parent(
                Vector2F::zero(),
                ParentOffsetBounds::WindowByPosition,
                ParentAnchor::TopRight,
                ChildAnchor::TopRight,
            ),
        );
    }

    fn render_new_session_button(&self, ctx: &AppContext) -> Box<dyn Element> {
        const CORNER_RADIUS: Radius = Radius::Pixels(4.);
        const BUTTON_HEIGHT: f32 = 24.;
        const SIDE_MENU_WIDTH: f32 = 16.;
        const BUTTON_WIDTH: f32 = 24. + SIDE_MENU_WIDTH;
        const BUTTON_LEFT_MARGIN: f32 = 4.;

        let new_tab_tool_tip_label_text = crate::t!("workspace-new-tab-tooltip");
        let new_tab_tool_tip_sublabel_text =
            keybinding_name_to_display_string(NEW_TAB_BINDING_NAME, ctx);
        let tab_configs_tool_tip_label_text = crate::t!("workspace-tab-configs-tooltip");
        let tab_configs_tool_tip_sublabel_text =
            keybinding_name_to_display_string(TOGGLE_TAB_CONFIGS_MENU_BINDING_NAME, ctx);
        let appearance = Appearance::as_ref(ctx);

        if !FeatureFlag::ShellSelector.is_enabled() {
            // Legacy new tab button, which shows the menu on right click.
            let new_tab_button = self
                .render_tab_bar_icon_button(
                    appearance,
                    icons::Icon::Plus,
                    &self.mouse_states.new_tab_button.clone(),
                    WorkspaceAction::AddTerminalTab {
                        hide_homepage: false,
                    },
                    new_tab_tool_tip_label_text,
                    new_tab_tool_tip_sublabel_text,
                    false,
                    false,
                )
                .on_right_click(move |ctx, _, position| {
                    ctx.dispatch_typed_action(WorkspaceAction::ToggleNewSessionMenu {
                        position,
                        is_vertical_tabs: false,
                    });
                })
                .finish();
            return Container::new(
                SavePosition::new(
                    Align::new(new_tab_button).finish(),
                    NEW_TAB_BUTTON_POSITION_ID,
                )
                .finish(),
            )
            .with_margin_left(BUTTON_LEFT_MARGIN)
            .finish();
        }

        let theme = appearance.theme();

        Hoverable::new(self.mouse_states.new_tab.clone(), |state| {
            let window_id = self.window_id;
            let is_active = self.show_new_session_dropdown_menu.is_some();

            let new_tab_button = combo_inner_button(
                appearance,
                icons::Icon::Plus,
                false,
                self.mouse_states.new_tab_button.clone(),
            )
            .with_style(
                UiComponentStyles::default()
                    .set_border_radius(CornerRadius::with_left(CORNER_RADIUS)),
            )
            .with_tooltip(self.render_tab_bar_icon_button_tooltip(
                appearance,
                new_tab_tool_tip_label_text.clone(),
                new_tab_tool_tip_sublabel_text.clone(),
            ))
            .build()
            .on_click(move |ctx, _, _| {
                ctx.dispatch_typed_action(WorkspaceAction::AddTerminalTab {
                    hide_homepage: false,
                });
            })
            .finish();

            let new_session_menu_button = combo_inner_button(
                appearance,
                icons::Icon::ChevronDown,
                is_active,
                self.mouse_states.new_tab_menu.clone(),
            )
            .with_style(
                UiComponentStyles::default()
                    .set_border_radius(CornerRadius::with_right(CORNER_RADIUS))
                    .set_width(SIDE_MENU_WIDTH),
            )
            .with_active_styles(
                UiComponentStyles::default()
                    .set_background(internal_colors::fg_overlay_3(theme).into()),
            )
            .with_tooltip(self.render_tab_bar_icon_button_tooltip(
                appearance,
                tab_configs_tool_tip_label_text.clone(),
                tab_configs_tool_tip_sublabel_text.clone(),
            ))
            .build()
            .on_click(move |ctx, app, _| {
                // We are positioning the menu to the lower-left corner of the new tab button.
                // This gives the impression that both individual buttons are one big button.
                if let Some(position) =
                    app.element_position_by_id_at_last_frame(window_id, NEW_TAB_BUTTON_POSITION_ID)
                {
                    ctx.dispatch_typed_action(WorkspaceAction::ToggleNewSessionMenu {
                        position: position.lower_left(),
                        is_vertical_tabs: false,
                    });
                }
            })
            .finish();

            let row = Flex::row()
                .with_cross_axis_alignment(CrossAxisAlignment::Center)
                .with_child(
                    SavePosition::new(
                        Align::new(new_tab_button).finish(),
                        NEW_TAB_BUTTON_POSITION_ID,
                    )
                    .finish(),
                )
                .with_child(
                    SavePosition::new(
                        Align::new(new_session_menu_button).finish(),
                        NEW_SESSION_MENU_BUTTON_POSITION_ID,
                    )
                    .finish(),
                )
                .finish();

            let mut ret = Container::new(
                ConstrainedBox::new(row)
                    .with_height(BUTTON_HEIGHT)
                    .with_width(BUTTON_WIDTH)
                    .finish(),
            )
            .with_corner_radius(CornerRadius::with_all(CORNER_RADIUS))
            .with_margin_left(BUTTON_LEFT_MARGIN);

            if state.is_hovered() {
                ret = ret.with_background(internal_colors::neutral_1(theme));
            }
            ret.finish()
        })
        .finish()
    }

    fn render_avatar_button(&self, appearance: &Appearance, ctx: &AppContext) -> Box<dyn Element> {
        let is_anonymous = self.auth_state.is_anonymous_or_logged_out();
        let display_name = self
            .auth_state
            .username_for_display()
            .unwrap_or(DEFAULT_USER_DISPLAY_NAME.to_owned());

        let avatar_content = if self.auth_state.is_anonymous_or_logged_out() {
            AvatarContent::Icon(icons::Icon::Gear)
        } else {
            self.auth_state
                .user_photo_url()
                .map(|url| AvatarContent::Image {
                    url,
                    display_name: display_name.clone(),
                })
                .unwrap_or(AvatarContent::DisplayName(display_name.clone()))
        };

        let mut avatar = Avatar::new(
            avatar_content,
            UiComponentStyles {
                width: Some(20.),
                height: Some(20.),
                border_radius: Some(CornerRadius::with_all(Radius::Percentage(50.))),
                font_family_id: Some(appearance.ui_font_family()),
                font_weight: Some(Weight::Bold),
                background: Some(appearance.theme().accent().into()),
                font_size: Some(12.),
                font_color: Some(ColorU::black()),
                ..Default::default()
            },
        );

        // Render the subtle autoupdate UI if autoupdate is ready and there is no incoming prominent update version.
        let autoupdate_stage = autoupdate::get_update_state(ctx);
        if FeatureFlag::AutoupdateUIRevamp.is_enabled()
            && autoupdate_stage.ready_for_update()
            && autoupdate_stage
                .available_new_version()
                .map(|version| {
                    !is_incoming_version_past_current(version.last_prominent_update.as_deref())
                })
                .unwrap_or(false)
        {
            avatar = avatar.with_status_element(
                StatusElementTypes::Circle,
                RedNotificationDot::default_styles(appearance),
            );
        }

        let button = Hoverable::new(self.mouse_states.avatar_icon.clone(), |state| {
            let mut stack = Stack::new();
            let mut container = Container::new(avatar.build().finish())
                .with_corner_radius(CornerRadius::with_all(Radius::Pixels(4.)))
                .with_uniform_padding(2.);

            if state.is_mouse_over_element() {
                if !state.is_clicked() {
                    container = container.with_background(appearance.theme().surface_2());
                }
                // On hover, show tooltip of user's display name (if it exists)
                if !self.is_user_menu_open && !is_anonymous {
                    stack.add_positioned_overlay_child(
                        appearance
                            .ui_builder()
                            .tool_tip(display_name.clone())
                            .with_style(UiComponentStyles {
                                background: Some(appearance.theme().tooltip_background().into()),
                                font_color: Some(appearance.theme().background().into_solid()),
                                ..Default::default()
                            })
                            .build()
                            .finish(),
                        OffsetPositioning::offset_from_parent(
                            vec2f(0., 4.),
                            ParentOffsetBounds::WindowByPosition,
                            ParentAnchor::BottomMiddle,
                            ChildAnchor::TopMiddle,
                        ),
                    );
                }
            }
            stack.add_child(container.finish());
            stack.finish()
        })
        .on_click(move |ctx, _, _| {
            ctx.dispatch_typed_action(WorkspaceAction::ToggleUserMenu);
        })
        .with_cursor(Cursor::PointingHand)
        .finish();

        SavePosition::new(Align::new(button).finish(), USER_AVATAR_BUTTON_POSITION_ID).finish()
    }

